function root() {
    let vh = $(window).height();
    let header = $("#header").outerHeight();
    let footer = $("#footer").outerHeight();
    document.documentElement.style.setProperty("--vh", vh + "px");
    document.documentElement.style.setProperty("--header", header + "px");
    document.documentElement.style.setProperty("--footer", footer + "px");
}
root();
$(window).on("resize", function () {
    setTimeout(function () {
        root();
    }, 100);
});

$(function () {
    if ($("body.layout").length) {
        $("#loading").addClass("off");
        $(".a-replace").each(function () {            
            const html = $(this).find(".rep").html();
            $(this).replaceWith(html);
        });
        $(".check-use").each(function () {
            if ($(this).find("[area_id]").css("display") == "none" || $(this).find("[data-use='off']").length || ($(this).find("img[src*='/']").length == 0 && $(this).text().trim().length == 0 && $(this).find("iframe").length == 0)) {
                $(this).remove();
            }
        });
        
        if (/^[a-z]+$/.test($(".a-header .visible .logo span").text())) {
            $(".a-header .visible .logo").addClass("low");
        }
        
        if ($(".main-sec1").length) {
            const cc = $(".main-sec1 .a-list:first-child a").attr("href");
            if (cc && cc.startsWith("//")) {
                $("body").addClass("cc");
            }
            $(".main-sec1 .a-wrap").append("<li class='last'></li>");
        	$(".main-sec1 .last").append($(".a-footer"));
            
            let logo;
            if ($(".a-header .visible .logo img[src*='/']").length) {
                logo = $(".a-header .visible .logo img").height();
            } else {
                logo = $(".a-header .visible .logo span").css("font-size");
            }
            $(".a-header .visible .logo").css("min-height", logo);
        }
        
        $(".a-section.add").each(function () {
            if ($(this).find("li").length < 4) {
                const li = $(this).find("ul").html();
                $(this).find("ul").html(li + li + li + li);
            }
        });
        
        if ($(".xans-product-relation").length) {
            const item = $(".xans-product-relation").clone();
            $(".xans-product-detail .infoArea").append(item);
        }
    }
});
